query:
SELECT ncaaName, primaryColor, secondaryColor, tertiaryColor FROM ncaam_teams WHERE LOWER(ncaaName) LIKE '%high point%' OR LOWER(vsinName) LIKE '%high point%';
SELECT COUNT(*) as total, SUM(CASE WHEN primaryColor IS NULL THEN 1 ELSE 0 END) as missing_primary FROM ncaam_teams;
SELECT ncaaName, primaryColor, secondaryColor FROM ncaam_teams WHERE primaryColor IS NULL ORDER BY ncaaName LIMIT 20;

